#include<bits/stdc++.h>
using namespace std;
int n, m;
int a[101][101];
int in[101];
int out[101];
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) {
		while(1){
			int x;
					cin >> x;
					if(x==0){
						break;
					}
					a[i][x] = 1;
					in[x]++;
					out[i]++;
		}

	}
	queue<int> q;
	for (int i = 1; i <= n; i++) {
		if (in[i] == 0) {
			q.push(i);
		}
	}
	while (!q.empty()) {
		int x = q.front();
		cout<<x<<' ';
		q.pop();
		for (int i = 1; i <= n; i++) {
			if (a[x][i]) {
				a[x][i] = 0;
				in[i]--;
				if (in[i] == 0) {
					q.push(i);
				}
				out[x]--;
			}
		}
	}
	return 0;
}
